import { PYTHON_BEGINNER, PYTHON_INTERMEDIATE, PYTHON_EXPERT } from './python';

// ─── Shared type helpers ──────────────────────────────────────────────────────
export interface MCQ { id: string; question: string; options: string[]; correct: string; explanation?: string }
export interface ToolIdQ { id: string; description: string; correctAnswer: string; keywords: string[] }
export interface PracticalQ { id: string; task: string; expectedKeywords: string[]; alternativeKeywords?: string[]; minLength: number; sampleSolution?: string }
export interface TestCase { input: string; expectedOutput: string; hidden: boolean }
export interface CodingQ { id: string; title: string; difficulty?: string; description: string; examples?: { input: string; output: string; explanation?: string }[]; testCases: TestCase[]; starterCode?: Record<string, string>; timeLimit?: number; memoryLimit?: number }
export interface ScenarioQ {
  id: string;
  question: string;
  minWords?: number;
  scoringKeywords?: string[];
  // Expert MCQ format (CHANGE: expert sections are answered as hard MCQs).
  // Author 4 close options + the correct letter ('A'-'D'); leave undefined until authored.
  options?: string[];
  correct?: string;
}
export interface CapstoneField { name: string; label: string; placeholder: string; required: boolean; minWords?: number }
export interface Capstone { instruction: string; fields: CapstoneField[]; githubEvalCriteria?: { languageMatch: string[]; testFilePatterns?: string[]; ciPatterns?: string[] } }

export interface BeginnerBank { mcq: MCQ[]; toolId: ToolIdQ[]; practical: PracticalQ[] }
export interface IntermediateBank { mcq: MCQ[]; coding: CodingQ[]; scenarios: ScenarioQ[]; framework: ScenarioQ[] }
export interface ExpertBank { scenarios: ScenarioQ[]; capstone: Capstone; mentoring: ScenarioQ[]; questionnaire: ScenarioQ[] }
export interface SkillBank { beginner: BeginnerBank; intermediate: IntermediateBank; expert: ExpertBank }

// ─── Utility: letter correct index → 0-based number ─────────────────────────
export function correctLetterToIndex(letter: string): number {
  return { A: 0, B: 1, C: 2, D: 3 }[letter.toUpperCase()] ?? 0;
}

// ─── Default capstone template (reused for many skills) ──────────────────────
function capstone(skill: string, langs: string[]): Capstone {
  return {
    instruction: `Submit a GitHub repository that demonstrates your ${skill} expertise. This should be a real project you built or significantly contributed to.`,
    fields: [
      { name: 'githubUrl', label: 'GitHub Repository URL', placeholder: 'https://github.com/username/repository', required: true },
      { name: 'projectDescription', label: 'Project Description', placeholder: 'Describe what this project does, the problem it solves and its scale/impact', required: true, minWords: 50 },
      { name: 'yourRole', label: 'Your Role', placeholder: 'Describe your specific contributions', required: true, minWords: 30 },
      { name: 'keyContributions', label: 'Key Technical Contributions', placeholder: 'List 3-5 specific technical decisions you made and why', required: true, minWords: 50 },
    ],
    githubEvalCriteria: { languageMatch: langs },
  };
}

