// Fallback bank for skills without dedicated MCQ functions — option A is always correct
function makeSimpleBank(skill: string, questions: string[]): SkillBank {
  const s = skill.substring(0, 3).toLowerCase().replace(/[^a-z]/g, '_');
  const mcqs: MCQ[] = questions.map((q, i) => {
    const conceptRaw = q.replace(/^What (?:is|are|does|do) /i, '').replace(/\?$/, '');
    const concept = conceptRaw.charAt(0).toUpperCase() + conceptRaw.slice(1);
    return {
      id: `${s}_b_${String(i + 1).padStart(3, '0')}`,
      question: q.endsWith('?') ? q : q + '?',
      options: [
        `${concept} — a standardised ${skill} concept used in professional testing environments`,
        `A one-time manual activity with no repeatable process or tooling`,
        `A legacy configuration approach phased out in modern CI/CD workflows`,
        `An internal metric tracked only by senior management, not by testing teams`,
      ],
      correct: 'A' as const,
    };
  });
  return {
    beginner: buildMinimalBeginnerBank(skill, mcqs),
    intermediate: buildMinimalIntermediateBank(skill, []),
    expert: buildMinimalExpertBank(skill),
  };
}

function buildRealBeginnerBank(skill: string, mcqs: MCQ[]): SkillBank {
  return {
    beginner: buildMinimalBeginnerBank(skill, mcqs),
    intermediate: buildMinimalIntermediateBank(skill, []),
    expert: buildMinimalExpertBank(skill),
  };
}

function buildRealSkillBank(skill: string, bMcqs: MCQ[], iMcqs: MCQ[]): SkillBank {
  return {
    beginner: buildMinimalBeginnerBank(skill, bMcqs),
    intermediate: buildMinimalIntermediateBank(skill, iMcqs),
    expert: buildMinimalExpertBank(skill),
  };
}

// Generic real MCQs for remaining skills using topic-specific content
function buildTopicMCQs(skill: string, pairs: [string, string[]][]): MCQ[] {
  return pairs.map(([q, opts], i) => ({
    id: `${skill.substring(0,3).toLowerCase().replace(/[^a-z]/g,'_')}_b_${String(i+1).padStart(3,'0')}`,
    question: q,
    options: opts,
    correct: 'A' as const,
  }));
}

