function regressionMCQs(): MCQ[] {
  return [
    { id:'reg_b_001', question:'What is the primary goal of regression testing?', options:['To verify that recent changes have not broken existing, previously working functionality','To test a feature for the very first time','To measure response time under heavy load','To validate the visual design against mockups'], correct:'A', explanation:'Regression testing confirms that new changes have not introduced defects in already-working areas.' },
    { id:'reg_b_002', question:'Regression testing is BEST triggered by which event?', options:['Gathering requirements','Writing the project charter','A code change such as a bug fix or enhancement','Closing the project'], correct:'C', explanation:'Any change to the codebase can introduce regressions, so it triggers regression testing.' },
    { id:'reg_b_003', question:'What is a regression test suite?', options:['A list of open defects','A maintained set of test cases re-run after changes to catch regressions','A performance benchmark','A single end-to-end test of the whole app'], correct:'B', explanation:'It is a curated, reusable collection of tests executed after changes.' },
    { id:'reg_b_004', question:'Which type of test is the BEST candidate for regression automation?', options:['A test that changes every sprint','A throwaway one-time test','A test for a feature still being designed','A stable, frequently executed test case'], correct:'D', explanation:'Stable, repeatable, high-value tests give the best automation ROI.' },
    { id:'reg_b_005', question:'What distinguishes retesting from regression testing?', options:['They are exactly the same activity','Retesting confirms a specific defect is fixed; regression checks the fix did not break other areas','Regression only runs on new code','Retesting can never be automated'], correct:'B', explanation:'Retesting validates a fix; regression validates surrounding functionality.' },
    { id:'reg_b_006', question:'What is impact analysis used for in regression testing?', options:['Measuring team velocity','Replacing the need to test','Identifying which areas a change may affect so the right tests are selected','Estimating server costs'], correct:'C', explanation:'Impact analysis scopes regression to the areas a change could affect.' },
    { id:'reg_b_007', question:'What is selective (partial) regression testing?', options:['Re-running only the subset of tests related to the changed area','Running the entire suite every time','Testing only the database','Skipping regression altogether'], correct:'A', explanation:'Selective regression runs only tests relevant to the change.' },
    { id:'reg_b_008', question:'How does a smoke test relate to regression?', options:['It is a complete regression run','It quickly verifies critical paths before deeper regression testing','It is a penetration test','It measures memory leaks'], correct:'B', explanation:'Smoke tests are a fast sanity check before fuller regression.' },
    { id:'reg_b_009', question:'Why can a regression suite become bloated over time?', options:['Because defects decrease','Because automation is removed','Because requirements never change','Because obsolete or duplicate test cases are not pruned'], correct:'D', explanation:'Without maintenance, redundant/obsolete tests accumulate.' },
    { id:'reg_b_010', question:'What is test case prioritisation in regression?', options:['Deleting all low-priority tests','Ordering tests so the most important/high-risk run first','Running tests alphabetically','Assigning tests to the newest tester'], correct:'B', explanation:'Prioritisation surfaces high-risk failures sooner.' },
    { id:'reg_b_011', question:'Which metric best indicates regression suite effectiveness?', options:['Number of testers on the team','Lines of code in the application','Defects caught by regression before release','Total meetings held'], correct:'C', explanation:'Catching regressions before release is the core value measure.' },
    { id:'reg_b_012', question:'What is a baseline in regression testing?', options:['A known, verified state of the application used for comparison after changes','The newest untested build','A list of testers','The production incident log'], correct:'A', explanation:'A baseline is the trusted reference state to compare against.' },
    { id:'reg_b_013', question:'When should the regression suite be updated?', options:['Never, to keep it stable','Whenever features are added, changed, or removed','Only at project end','Only when a tester leaves'], correct:'B', explanation:'The suite must evolve with the product to stay relevant.' },
    { id:'reg_b_014', question:'What is the main benefit of running regression tests in CI/CD?', options:['It removes the need for developers','It eliminates all bugs permanently','It slows releases for safety','It catches regressions automatically and early on every build'], correct:'D', explanation:'CI regression gives fast, automatic feedback on every change.' },
    { id:'reg_b_015', question:'A flaky regression test is one that:', options:['Always passes','Passes and fails intermittently without code changes','Tests pastry recipes','Only runs in production'], correct:'B', explanation:'Flaky tests are non-deterministic and erode trust in the suite.' },
    { id:'reg_b_016', question:'Which is a sign you need MORE regression coverage?', options:['All releases are defect-free','Tests never change','Recurring defects keep reappearing in already-shipped features','The team is small'], correct:'C', explanation:'Reappearing defects indicate coverage gaps.' },
    { id:'reg_b_017', question:'What is full regression testing?', options:['Re-executing the entire regression suite across the application','Testing only one screen','Running only new test cases','A single smoke test'], correct:'A', explanation:'Full regression re-runs the complete suite, typically before major releases.' },
    { id:'reg_b_018', question:'Why is test data management important for regression?', options:["It isn't relevant",'Consistent, reliable test data makes regression results repeatable and trustworthy','It only matters for performance tests','It replaces assertions'], correct:'B', explanation:'Stable data keeps regression results deterministic.' },
    { id:'reg_b_019', question:'Which practice reduces regression execution time the most?', options:['Running everything manually','Adding more meetings','Disabling assertions','Parallel execution of automated tests'], correct:'D', explanation:'Parallelisation dramatically shortens suite runtime.' },
    { id:'reg_b_020', question:'What is risk-based regression testing?', options:['Testing randomly','Focusing regression effort on the highest-risk and most-used areas first','Only testing low-risk areas','Avoiding testing risky features'], correct:'B', explanation:'Risk-based testing concentrates effort where failure impact is greatest.' },
  ];
}
function regressionMCQsInt(): MCQ[] {
  return [
    { id:'reg_i_001', question:'In a CI pipeline with a 2-hour full regression suite and 20 commits/day, what is the BEST strategy?', options:['Run full regression on every commit regardless of time','Run a fast smoke/impacted subset per commit and full regression nightly','Stop running regression','Run regression only weekly'], correct:'B', explanation:'Tiered execution balances fast feedback with full coverage.' },
    { id:'reg_i_002', question:'A change to a shared utility module is deployed. Which regression scope is most appropriate?', options:['Test only the utility module in isolation','Skip regression because it is just a utility','Regress all modules that depend on that utility (impact-based selection)','Run only UI tests'], correct:'C', explanation:'Shared code has wide blast radius; test all dependents.' },
    { id:'reg_i_003', question:'Your automated regression suite has 15% flaky tests failing CI randomly. Best first action?', options:['Delete all failing tests','Quarantine flaky tests, root-cause the instability, then re-enable','Ignore CI failures','Re-run until green and ship'], correct:'B', explanation:'Quarantine + root-cause preserves signal without losing coverage.' },
    { id:'reg_i_004', question:'Which approach gives the fastest feedback while preserving safety in regression?', options:['One giant sequential test','Manual regression only','Running tests in random order','Test impact analysis + parallelisation + tiered suites'], correct:'D', explanation:'Combining selection, parallelism and tiers optimises speed and safety.' },
    { id:'reg_i_005', question:'Regression suite runtime grew from 20 to 90 minutes. Most sustainable fix?', options:['Buy faster laptops for testers','Prune redundant cases, parallelise, and apply coverage-based selection','Remove assertions to speed it up','Run it less often'], correct:'B', explanation:'Maintenance + parallelism + selection addresses the root cause.' },
    { id:'reg_i_006', question:'After a hotfix in production, what regression should run before redeploy?', options:['Full multi-day regression','No regression — it is urgent','Targeted regression around the fix plus a critical-path smoke suite','Only performance tests'], correct:'C', explanation:'Targeted + smoke gives confidence quickly for urgent fixes.' },
    { id:'reg_i_007', question:'What is the role of code coverage data in regression test selection?', options:['It maps which tests exercise changed code so only relevant tests are selected','It guarantees zero defects','It measures tester productivity','It replaces requirements'], correct:'A', explanation:'Coverage linkage enables precise test impact analysis.' },
    { id:'reg_i_008', question:'A regression defect escaped to production. Best preventative follow-up?', options:['Blame the developer','Add a regression test reproducing the defect so it can never silently return','Remove the feature','Disable that test area'], correct:'B', explanation:'A reproducing test prevents recurrence and documents the bug.' },
    { id:'reg_i_009', question:'Strongest indicator that automation ROI for regression is positive?', options:['The suite has many tests','Tests use the newest framework','Automation took a long time to build','Manual effort and escaped defects dropped while release frequency rose'], correct:'D', explanation:'Outcome metrics (less manual effort, fewer escapes, faster releases) prove ROI.' },
    { id:'reg_i_010', question:'How should regression tests handle frequently changing dynamic data (dates, IDs)?', options:['Hard-code expected values','Use data-independent assertions, fixtures, or normalisation to avoid brittleness','Skip those tests','Only test in production'], correct:'B', explanation:'Avoiding hard-coded volatile data prevents false failures.' },
    { id:'reg_i_011', question:'What is the purpose of a regression gate in CI/CD?', options:['To slow developers down','To allow any build to deploy','To block promotion of a build when critical regression tests fail','To format the code'], correct:'C', explanation:'A quality gate stops bad builds from progressing.' },
    { id:'reg_i_012', question:'Two regression tests pass alone but fail when run together. Likely cause?', options:['A compiler bug','Shared/leaking state or test interdependence (ordering, data not reset)','Too few tests','Network speed only'], correct:'B', explanation:'Inter-test state leakage causes order-dependent failures.' },
    { id:'reg_i_013', question:'Which strategy best balances coverage and speed for a large product?', options:['Tiered suites: smoke (PR) -> impacted regression (merge) -> full regression (nightly)','Run everything on every keystroke','Only nightly full runs and nothing else','Manual regression each sprint'], correct:'A', explanation:'Tiering provides graduated confidence at each stage.' },
    { id:'reg_i_014', question:'What makes a regression suite maintainable?', options:['Maximum number of tests','No documentation','Hard-coded waits everywhere','Clear naming, no duplication, stable locators/data, and shared utilities'], correct:'D', explanation:'Clean structure and stability keep maintenance cost low.' },
    { id:'reg_i_015', question:'How do you decide a test should LEAVE the regression suite?', options:['When it passes once','When the feature is removed/obsolete or the case is redundant with better coverage','Never remove tests','When the author leaves the team'], correct:'B', explanation:'Prune obsolete/redundant tests to keep the suite lean and meaningful.' },
  ];
}
function uatMCQs(): MCQ[] {
  return [
    { id:'uat_b_001', question:'What does UAT stand for?', options:['User Acceptance Testing','Unit Automation Testing','Universal Application Test','Usability Analysis Tool'], correct:'A', explanation:'UAT = User Acceptance Testing, the final business validation.' },
    { id:'uat_b_002', question:'Who primarily performs UAT?', options:['Only developers','End users or business representatives who will use the system','The security team only','Automated robots exclusively'], correct:'B', explanation:'Business users validate the system against real needs.' },
    { id:'uat_b_003', question:'What is the main goal of UAT?', options:['To find memory leaks','To check code syntax','To confirm the system meets business requirements and is fit for real-world use','To measure CPU usage'], correct:'C', explanation:'UAT verifies business fitness, not low-level technical concerns.' },
    { id:'uat_b_004', question:'When does UAT typically occur?', options:['Before requirements are written','During unit testing','At the very start of coding','After system/integration testing, before go-live'], correct:'D', explanation:'UAT is the last validation gate before production.' },
    { id:'uat_b_005', question:'What is acceptance criteria?', options:['A list of bugs','Predefined conditions a feature must satisfy to be accepted by the business','The server configuration','A performance benchmark'], correct:'B', explanation:'Acceptance criteria define when work is "done" for the business.' },
    { id:'uat_b_006', question:'What is a UAT sign-off?', options:['Formal business approval that the system is acceptable for production','A developer code review','A load-test report','A list of unit tests'], correct:'A', explanation:'Sign-off is formal stakeholder acceptance to proceed.' },
    { id:'uat_b_007', question:'Which environment is most appropriate for UAT?', options:["The developer's local machine",'The production environment with live customers','A dedicated UAT environment that mirrors production with realistic data','No environment is needed'], correct:'C', explanation:'A production-like UAT environment gives realistic, safe validation.' },
    { id:'uat_b_008', question:'What is the difference between alpha and beta testing?', options:['There is no difference','Alpha is internal in-house testing; beta is by real external users before release','Beta is always before alpha','Alpha is only automated'], correct:'B', explanation:'Alpha = internal, beta = external real users.' },
    { id:'uat_b_009', question:'What kind of test cases are typically used in UAT?', options:['Low-level unit tests','Compiler tests','Memory profiling scripts','Real-world business scenarios and end-to-end workflows'], correct:'D', explanation:'UAT exercises realistic business workflows.' },
    { id:'uat_b_010', question:'Why is realistic test data important in UAT?', options:["It isn't important",'It lets users validate the system against true business situations','It speeds up compilation','It reduces source code size'], correct:'B', explanation:'Realistic data exposes real-world issues users care about.' },
    { id:'uat_b_011', question:'What is a Go/No-Go decision in UAT?', options:['A decision on whether the system is ready to go live based on UAT results','A choice of programming language','A server restart policy','A code-merge approval'], correct:'A', explanation:'Go/No-Go is the launch-readiness decision informed by UAT.' },
    { id:'uat_b_012', question:'Who usually writes UAT test scenarios?', options:['Only the database admin','Only the build server','Business users/analysts, often with QA support, based on real use cases','The compiler'], correct:'C', explanation:'Scenarios come from those who understand the business process.' },
    { id:'uat_b_013', question:'What should happen when a defect is found during UAT?', options:['Ignore it and go live','Log it, assess business impact, and decide fix vs accept before go-live','Delete the feature immediately','Restart the project'], correct:'B', explanation:'Defects are triaged by business impact for a launch decision.' },
    { id:'uat_b_014', question:'What is business process testing in UAT?', options:['Testing only one button','Checking code coverage','Measuring network latency','Validating complete end-to-end business workflows the way users perform them'], correct:'D', explanation:'It validates whole processes, not isolated functions.' },
    { id:'uat_b_015', question:'Which statement about UAT and functional testing is correct?', options:['They are identical','Functional testing checks the system works as specified; UAT checks it works for the business','UAT happens before functional testing','Functional testing is done by customers'], correct:'B', explanation:'Functional = meets spec; UAT = meets business need.' },
    { id:'uat_b_016', question:'What is a parallel run in UAT?', options:['Running the new system alongside the old one to compare results before switching','Running two unit tests at once','Two developers coding together','Duplicate databases for backup'], correct:'A', explanation:'Parallel runs de-risk cutover by comparing old vs new outputs.' },
    { id:'uat_b_017', question:'What is the risk of skipping UAT?', options:['Faster, safer releases','Better code coverage','Shipping a system that technically works but does not meet real business needs','Lower infrastructure cost'], correct:'C', explanation:'Without UAT, business-fit gaps surface only after launch.' },
    { id:'uat_b_018', question:'What is exploratory UAT?', options:['Following a fixed script exactly','Users freely exploring the system to uncover issues beyond scripted cases','Automated regression','A security audit'], correct:'B', explanation:'Exploratory UAT finds issues scripted cases miss.' },
    { id:'uat_b_019', question:'Which document typically guides UAT execution?', options:['The source code','The database schema','The CI pipeline config','UAT test scripts derived from acceptance criteria and business requirements'], correct:'D', explanation:'UAT scripts trace back to acceptance criteria.' },
    { id:'uat_b_020', question:'What is the best measure of UAT success?', options:['Number of lines tested','Business stakeholders confirm the system meets their needs and sign off','CPU utilisation stays low','The number of automated tests'], correct:'B', explanation:'Stakeholder acceptance is the definitive UAT success signal.' },
  ];
}
