function jiraMCQs(): MCQ[] {
  return [
    { id:'jir_b_001', question:'What is JIRA primarily used for?', options:['Compiling source code','Issue tracking and agile project management','Database administration','Network monitoring'], correct:'B', explanation:'JIRA tracks issues and supports agile workflows.' },
    { id:'jir_b_002', question:'What is an Epic in JIRA?', options:['A large body of work that can be broken down into smaller stories','A single line of code','A server log','A type of user permission'], correct:'A', explanation:'An epic groups related stories toward a larger goal.' },
    { id:'jir_b_003', question:'What is a Sprint in JIRA?', options:['A permanent backlog','A bug report','A fixed time-boxed iteration in which a team completes selected work','A deployment server'], correct:'C', explanation:'A sprint is a time-boxed delivery iteration.' },
    { id:'jir_b_004', question:'What does JQL stand for?', options:['Java Query Logic','JIRA Quick Link','Joint Query Layer','JIRA Query Language'], correct:'D', explanation:'JQL is JIRA Query Language for searching issues.' },
    { id:'jir_b_005', question:'What is the Backlog in JIRA?', options:['A list of completed tasks','A prioritised list of work not yet scheduled into a sprint','A server error log','A user directory'], correct:'B', explanation:'The backlog holds prioritised, unscheduled work.' },
    { id:'jir_b_006', question:'What is a user Story in JIRA?', options:['A small unit of work describing a feature from the user perspective','A database table','A build pipeline','A permission scheme'], correct:'A', explanation:'Stories express requirements from the user viewpoint.' },
    { id:'jir_b_007', question:'What does a JIRA workflow define?', options:['The colour scheme of the board','The number of users','The set of statuses and transitions an issue moves through','The server backup schedule'], correct:'C', explanation:'Workflows model an issue\'s lifecycle states and transitions.' },
    { id:'jir_b_008', question:'What is a Kanban board used for in JIRA?', options:['Time-boxed sprints only','Visualising continuous flow of work across columns, often with WIP limits','Storing source code','Running automated tests'], correct:'B', explanation:'Kanban visualises flow and limits work in progress.' },
    { id:'jir_b_009', question:'What are story points used for?', options:['Counting bugs','Measuring server uptime','Tracking login attempts','Estimating the relative effort/complexity of a story'], correct:'D', explanation:'Story points estimate relative size, not hours.' },
    { id:'jir_b_010', question:'What is a Sub-task in JIRA?', options:['A separate project','A smaller piece of work that breaks down a parent issue','A user role','A dashboard gadget'], correct:'B', explanation:'Sub-tasks decompose a parent issue into steps.' },
    { id:'jir_b_011', question:'What is a burndown chart?', options:['A chart showing remaining work versus time in a sprint','A chart of server temperature','A list of users','A code coverage report'], correct:'A', explanation:'Burndown tracks remaining work over the sprint.' },
    { id:'jir_b_012', question:'What is a JIRA component?', options:['A hardware part','A type of chart','A sub-section of a project used to group issues','A sprint'], correct:'C', explanation:'Components group issues by area (e.g., Login, Payments).' },
    { id:'jir_b_013', question:'What is velocity in Scrum/JIRA?', options:['Network speed','The average story points a team completes per sprint','The number of testers','Deployment frequency'], correct:'B', explanation:'Velocity is average completed points per sprint, used for planning.' },
    { id:'jir_b_014', question:'What is a JIRA filter?', options:['A spam filter for email','A way to hide users','A firewall rule','A saved JQL search that returns a set of issues'], correct:'D', explanation:'Filters are saved JQL queries powering boards and dashboards.' },
    { id:'jir_b_015', question:'What is the purpose of labels in JIRA?', options:['To delete issues','To tag issues with keywords for easy grouping and searching','To compile code','To assign passwords'], correct:'B', explanation:'Labels are flexible tags for grouping and filtering.' },
    { id:'jir_b_016', question:'What is a JIRA dashboard?', options:['A customisable page of gadgets showing project info, charts, and filters','A database backup','A source code editor','A user password vault'], correct:'A', explanation:'Dashboards aggregate gadgets for at-a-glance status.' },
    { id:'jir_b_017', question:'What is a version (release) in JIRA?', options:['A user account type','A board column','A milestone grouping issues to be delivered in a release','A JQL function'], correct:'C', explanation:'Versions group issues for a release and feed release reports.' },
    { id:'jir_b_018', question:'What does assigning an issue to a user do?', options:['Deletes the issue','Makes that user responsible for working on it','Closes the sprint','Changes the project key'], correct:'B', explanation:'Assignee denotes ownership of the issue.' },
    { id:'jir_b_019', question:'Which JQL clause finds issues assigned to the current user?', options:['status = done','project = ABC','created > -1d','assignee = currentUser()'], correct:'D', explanation:'currentUser() resolves to the logged-in user.' },
    { id:'jir_b_020', question:"What is the benefit of linking issues (e.g., 'blocks', 'relates to')?", options:['It deletes duplicates automatically','It shows dependencies and relationships between issues','It compiles the project','It resets the workflow'], correct:'B', explanation:'Issue links surface dependencies and context.' },
  ];
}
function jiraMCQsInt(): MCQ[] {
  return [
    { id:'jir_i_001', question:'You need all unresolved bugs in project PAY assigned to you, ordered by priority. Which JQL is correct?', options:['project = PAY AND type = Story','project = PAY AND issuetype = Bug AND resolution = Unresolved AND assignee = currentUser() ORDER BY priority DESC','assignee = currentUser() ORDER BY created','status = Done AND project = PAY'], correct:'B', explanation:'It filters project, type, resolution, assignee and sorts by priority.' },
    { id:'jir_i_002', question:'A team wants to limit work-in-progress to improve flow. Which JIRA feature enforces this?', options:['Story points','Epics','WIP limits on Kanban board columns','Labels'], correct:'C', explanation:'Column WIP limits constrain concurrent work.' },
    { id:'jir_i_003', question:'How can you automate transitioning an issue to Done when a PR is merged?', options:['Manually edit the database','Use JIRA automation rules / smart commits with the VCS integration','Delete and recreate the issue','Change the project key'], correct:'B', explanation:'Automation rules / smart commits drive transitions from VCS events.' },
    { id:'jir_i_004', question:'Velocity dropped for 3 sprints while scope is stable. What do you investigate first using JIRA data?', options:['The dashboard colour theme','Number of labels used','The project icon','Sprint reports, blockers/flagged issues, and carry-over to find impediments'], correct:'D', explanation:'Sprint reports and blockers reveal the impediments behind the drop.' },
    { id:'jir_i_005', question:'What is the best use of a JIRA workflow condition?', options:['To change board colours','To restrict who or what can perform a status transition','To estimate story points','To create dashboards'], correct:'B', explanation:'Conditions gate transitions by role/criteria.' },
    { id:'jir_i_006', question:'A board shows issues from multiple projects. How is this typically achieved?', options:["The board's filter (JQL) spans multiple projects",'It is impossible in JIRA','By merging the projects databases','By disabling permissions'], correct:'A', explanation:'A board is backed by a filter that can span projects.' },
    { id:'jir_i_007', question:'How do you measure cycle time in JIRA?', options:['Count the number of comments','Sum all story points ever created','Use Control Chart / time an issue spends from In Progress to Done','Count the assignees'], correct:'C', explanation:'Control charts measure status-to-status duration.' },
    { id:'jir_i_008', question:'Stakeholders want a live view of release readiness. Best JIRA artefact?', options:['A single static screenshot','A Release/Version report or dashboard with status of issues in the fix version','The audit log','A list of labels'], correct:'B', explanation:'Release/Version reports show progress toward a release.' },
    { id:'jir_i_009', question:'What is the risk of overusing sub-tasks for everything?', options:['Faster sprints','Better velocity','Nothing, it is always good','Excessive granularity adds overhead and clutters reporting'], correct:'D', explanation:'Over-decomposition increases admin overhead and noise.' },
    { id:'jir_i_010', question:'How should you handle a recurring defect pattern across sprints in JIRA?', options:['Close them as duplicates without analysis','Use labels/components and a filter to track the pattern, then raise a root-cause/tech-debt epic','Delete the bugs','Reassign to a new user'], correct:'B', explanation:'Tracking + root-cause epic addresses the systemic issue.' },
    { id:'jir_i_011', question:'What does a cumulative flow diagram (CFD) reveal?', options:['Server CPU usage','The number of dashboards','Work distribution across statuses over time, exposing bottlenecks and growing WIP','The list of project admins'], correct:'C', explanation:'A CFD highlights bottlenecks and WIP growth.' },
    { id:'jir_i_012', question:'Best practice for a shared JIRA workflow used by many teams?', options:['Let every team freely edit the global workflow','Govern a standard workflow centrally and use schemes; customise per-project only where justified','Disable workflows entirely','Give all users admin rights'], correct:'B', explanation:'Central governance with schemes balances consistency and flexibility.' },
    { id:'jir_i_013', question:"An issue can't transition to 'In Review'. Most likely cause?", options:['A workflow condition/validator or missing required field blocks the transition','The internet is down','Too many labels','The sprint is named incorrectly'], correct:'A', explanation:'Validators/conditions/required fields commonly block transitions.' },
    { id:'jir_i_014', question:'How do you report work completed vs committed in a sprint?', options:['Count comments','Use the backlog only','Read the audit log line by line','Use the Sprint Report (committed vs completed, scope changes, incomplete issues)'], correct:'D', explanation:'The Sprint Report contrasts commitment with completion.' },
    { id:'jir_i_015', question:'Most effective way to keep the backlog healthy?', options:['Never groom it','Regular backlog refinement: prioritise, estimate, split large stories, remove stale items','Add every idea as a high priority','Delete the backlog each sprint'], correct:'B', explanation:'Ongoing refinement keeps the backlog actionable.' },
  ];
}
function testRailMCQs(): MCQ[] {
  return [
    { id:'tsr_b_001', question:'What is TestRail primarily used for?', options:['Writing production code','Managing test cases, runs, and results','Monitoring servers','Designing UI mockups'], correct:'B', explanation:'TestRail is a test case management tool.' },
    { id:'tsr_b_002', question:'What is a Test Case in TestRail?', options:['A documented set of steps and expected results to verify a specific condition','A deployment script','A user account','A database backup'], correct:'A', explanation:'A test case defines steps and expected outcomes.' },
    { id:'tsr_b_003', question:'What is a Test Suite in TestRail?', options:['A single test result','A type of report only','A collection of related test cases','A server cluster'], correct:'C', explanation:'A suite organises related test cases.' },
    { id:'tsr_b_004', question:'What is a Test Run in TestRail?', options:['A list of users','A permanent archive of code','A workflow diagram','An execution of selected test cases where results are recorded'], correct:'D', explanation:'A run captures execution results for chosen cases.' },
    { id:'tsr_b_005', question:'What is a Test Plan in TestRail?', options:['A single test case','A container that groups multiple test runs (often across configurations)','A defect report','A login page'], correct:'B', explanation:'A plan bundles multiple runs, often by configuration.' },
    { id:'tsr_b_006', question:'What is a Milestone in TestRail?', options:['A target such as a release or sprint that runs/plans can be associated with','A failed test','A type of user role','A database index'], correct:'A', explanation:'Milestones tie testing to releases/sprints.' },
    { id:'tsr_b_007', question:'What does a Section do in a TestRail suite?', options:['Stores passwords','Runs the tests automatically','Groups/organises test cases into logical folders','Deploys the build'], correct:'C', explanation:'Sections are folders that structure cases.' },
    { id:'tsr_b_008', question:'What statuses can a test result typically have in TestRail?', options:['Only Pass','Passed, Failed, Blocked, Retest, Untested (and custom statuses)','Only Open and Closed','Only True and False'], correct:'B', explanation:'TestRail supports several built-in and custom statuses.' },
    { id:'tsr_b_009', question:'How does TestRail support traceability?', options:['By compiling code','By hosting the application','By measuring CPU','By linking test cases to requirements and defects'], correct:'D', explanation:'References/integrations link cases to requirements and defects.' },
    { id:'tsr_b_010', question:'What is the TestRail API used for?', options:['Editing the operating system','Programmatically pushing automated test results and managing cases/runs','Rendering charts in the browser only','Backing up the database'], correct:'B', explanation:'The API integrates automation and external tools.' },
    { id:'tsr_b_011', question:'What is the benefit of a test case template in TestRail?', options:['It standardises the fields/format testers use to write cases','It runs tests automatically','It deletes old cases','It assigns passwords'], correct:'A', explanation:'Templates enforce consistent case structure.' },
    { id:'tsr_b_012', question:'What does test coverage reporting in TestRail show?', options:['Server uptime','Network bandwidth','How much of the requirements/features are covered by cases and results','Code compilation time'], correct:'C', explanation:'Coverage reports expose untested requirements.' },
    { id:'tsr_b_013', question:'What is a configuration in a TestRail test plan?', options:["A user's password",'A variation (e.g., browser/OS) against which the same cases are run','A defect status','A milestone date'], correct:'B', explanation:'Configurations run the same cases across environments.' },
    { id:'tsr_b_014', question:'Why integrate TestRail with JIRA?', options:['To compile JIRA','To replace JIRA entirely','To store source code','To link cases/results with requirements and push defects automatically'], correct:'D', explanation:'Integration gives end-to-end traceability and defect creation.' },
    { id:'tsr_b_015', question:'What is a custom field in TestRail used for?', options:['To delete test runs','To capture additional case/result data specific to your process','To restart the server','To change the theme'], correct:'B', explanation:'Custom fields tailor TestRail to your process.' },
    { id:'tsr_b_016', question:'What does the Blocked result status mean?', options:['The test could not be executed due to an external impediment','The test passed','The test was deleted','The test is automated'], correct:'A', explanation:'Blocked means execution was prevented (e.g., environment down).' },
    { id:'tsr_b_017', question:'What is the purpose of assigning a test to a user in a run?', options:['To delete it','To compile it','To make that tester responsible for executing it','To change its ID'], correct:'C', explanation:'Assignment denotes who runs the test.' },
    { id:'tsr_b_018', question:'What is a separated test step in TestRail?', options:['A single combined description only','Individual ordered actions each with their own expected result','A server log line','A type of milestone'], correct:'B', explanation:'Separated steps pair each action with an expected result.' },
    { id:'tsr_b_019', question:'Which TestRail feature helps track progress of an ongoing run?', options:['The login page','The API key','The user list','Progress/summary reports and dashboards (passed/failed/untested)'], correct:'D', explanation:'Dashboards/reports show live run progress.' },
    { id:'tsr_b_020', question:'What is the automation status field commonly used for?', options:["To store the tester's password",'To mark whether a case is automated, planned, or manual','To deploy code','To delete the suite'], correct:'B', explanation:'It tracks automation coverage across the case repository.' },
  ];
}
function testRailMCQsInt(): MCQ[] {
  return [
    { id:'tsr_i_001', question:'Your CI runs 5,000 automated tests nightly. Best way to get results into TestRail?', options:['Manually enter each result','Use the TestRail API to bulk-add results to a run created per build','Email a spreadsheet','Screenshot the console'], correct:'B', explanation:'The API automates bulk result reporting per build.' },
    { id:'tsr_i_002', question:'You must run the same 300 cases across Chrome, Firefox, and Edge. Best TestRail structure?', options:['Create 900 separate cases','Run them once and assume parity','A test plan with 3 configurations referencing the same cases','Three unrelated projects'], correct:'C', explanation:'Configurations reuse cases across environments.' },
    { id:'tsr_i_003', question:'How do you ensure requirements are fully covered before a release in TestRail?', options:['Count the number of testers','Link cases to requirements and use coverage/traceability reports to find gaps','Only run smoke tests','Check server logs'], correct:'B', explanation:'Traceability reports expose coverage gaps.' },
    { id:'tsr_i_004', question:"A nightly automated run shows many 'Blocked' results. What does this most likely indicate?", options:['All features work perfectly','The cases are obsolete','The tests are too fast','An environment/dependency problem prevented execution'], correct:'D', explanation:'Mass blocked results usually mean an environment failure.' },
    { id:'tsr_i_005', question:'Best practice for organising a large, growing case repository?', options:['One giant flat list','Logical suites and sections by feature/area, with templates and naming conventions','Random order','Delete old cases monthly regardless of value'], correct:'B', explanation:'Structured suites/sections keep large repositories maintainable.' },
    { id:'tsr_i_006', question:'How can TestRail reporting help identify flaky areas?', options:['Trend/comparison reports showing cases that frequently switch Pass/Fail across runs','The API key page','The milestone colour','User permission report'], correct:'A', explanation:'Trend reports reveal unstable cases over time.' },
    { id:'tsr_i_007', question:'You integrated TestRail with JIRA. A test fails — efficient workflow?', options:['Recreate the bug manually in three tools','Ignore it','Push/link a JIRA defect from the failed result so traceability is automatic','Email the developer a screenshot only'], correct:'C', explanation:'Linking a defect from the result preserves traceability.' },
    { id:'tsr_i_008', question:'Why separate test cases (repository) from test runs (execution)?', options:['There is no reason','Reusable cases stay version-controlled while each run records point-in-time results for a build','To slow testers down','To duplicate data'], correct:'B', explanation:'Separation enables reuse and historical run records.' },
    { id:'tsr_i_009', question:'What is the value of milestones tied to runs/plans?', options:['They compile code','They store passwords','They replace test cases','They give release-level visibility of test progress and quality'], correct:'D', explanation:'Milestones provide release-level reporting.' },
    { id:'tsr_i_010', question:'An automated result push via API keeps failing with 400. Most likely cause?', options:['The server is on fire','Invalid payload/field mapping or wrong run/case IDs in the request','Too many testers','The milestone name is long'], correct:'B', explanation:'HTTP 400 indicates a malformed request/IDs.' },
    { id:'tsr_i_011', question:'How do you report tested vs untested coverage to management each release?', options:['Verbally','Count commits','Use TestRail dashboards/reports filtered by milestone showing pass/fail/untested and requirement coverage','Read raw API logs'], correct:'C', explanation:'Milestone-filtered reports communicate coverage clearly.' },
    { id:'tsr_i_012', question:'Best approach when the same defect blocks many cases in a run?', options:['Mark each Passed to keep numbers green','Mark affected cases Blocked, reference the defect, and re-run after the fix','Delete the cases','Close the run early'], correct:'B', explanation:'Blocked + defect reference preserves accurate status.' },
    { id:'tsr_i_013', question:'What makes a TestRail case good for both manual and automated use?', options:['Clear steps/expected results, stable references, and an automation-status field','As many steps as possible','No expected results','Hard-coded environment IPs in every step'], correct:'A', explanation:'Clarity, stable references and automation tracking serve both.' },
    { id:'tsr_i_014', question:'How do configurations improve cross-platform reporting?', options:['They hide failures','They reduce the number of cases to write to zero','They compile platform code','They let you see results per environment within one plan'], correct:'D', explanation:'Per-configuration results pinpoint which environment failed.' },
    { id:'tsr_i_015', question:'Most sustainable way to keep automated and manual results unified?', options:['Two separate tools that never sync','Push automation results via API into the same TestRail runs/milestones used for manual execution','Only track manual results','Keep automation results in email'], correct:'B', explanation:'Unifying results in TestRail gives one source of truth.' },
  ];
}

